/* envmap.js — HDRI環境マップを RGBM 符号化で焼き込み（fetch不要・file://可）
 * hdri-skies.com の 751 / 758 を 2000x1000 から間引き＋プレフィルタ。
 * mips[0]=最も鮮鋭(256x128, 背景/鏡面反射), 以降ラフネス用にぼかし。irr=拡散用放射照度。
 * RGBM: linear = rgb * a * RANGE。グローバル: window.ENVMAPS */
(function(global){
  global.ENVMAPS = { range:16.0, order:["751","758"], labels:{"751":"Sky 751","758":"Sky 758"}, maps:{"751":{mips:[{w:256,h:128,d:""},{w:128,h:64,d:""},{w:64,h:32,d:""},{w:32,h:16,d:""},{w:16,h:8,d:""}],irr:{w:32,h:16,d:""}},"758":{mips:[{w:256,h:128,d:""},{w:128,h:64,d:""},{w:64,h:32,d:""},{w:32,h:16,d:""},{w:16,h:8,d:""}],irr:{w:32,h:16,d:""}}} };
})(window);
